class Solution:
    def findMaximumNumber(self, k, x):
        def accumulated_price(n):
            total = 0
            p = x
            while (1 << (p - 1)) <= n:
                cycle = 1 << p
                full = n // cycle
                remainder = n % cycle
                half = 1 << (p - 1)
                total += full * half + max(0, remainder - half + 1)
                p += x
            return total
        lo, hi = 1, 10**15
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if accumulated_price(mid) <= k:
                lo = mid
            else:
                hi = mid - 1
        return lo

