var findMaximumNumber = function(k, x) {
    function accumulatedPrice(n) {
        let total = BigInt(0);
        let p = x;
        const N = BigInt(n);
        while ((BigInt(1) << BigInt(p - 1)) <= N) {
            const cycle = BigInt(1) << BigInt(p);
            const half = BigInt(1) << BigInt(p - 1);
            const full = N / cycle;
            const rem = N % cycle;
            total += full * half + (rem > half - BigInt(1) ? rem - half + BigInt(1) : BigInt(0));
            p += x;
        }
        return total;
    }
    const K = BigInt(k);
    let lo = BigInt(1), hi = BigInt(1) << BigInt(50);
    while (lo < hi) {
        const mid = (lo + hi + BigInt(1)) / BigInt(2);
        if (accumulatedPrice(mid) <= K) lo = mid;
        else hi = mid - BigInt(1);
    }
    return Number(lo);
};
